```csharp
using Pfm.Categorization.WebApi.Domain.Categorize;
using Pfm.Categorization.WebApi.Infrastructure.Decisions;
using Pfm.Categorization.WebApi.Observability;

namespace Pfm.Categorization.WebApi;

public class Program
{
    public static void Main(string[] args)
    {
        var builder = WebApplication.CreateBuilder(args);

        // Add services to the container.
        builder.Services.AddControllers()
            .AddJsonOptions(options =>
            {
                // Campos nulos (ex.: "explain", opcional) não vão para o JSON — mesmo
                // comportamento documentado no contrato categorize (spec F1-PBI-1).
                options.JsonSerializerOptions.DefaultIgnoreCondition =
                    System.Text.Json.Serialization.JsonIgnoreCondition.WhenWritingNull;
            });

        // Learn more about configuring Swagger/OpenAPI at https://aka.ms/aspnetcore/swashbuckle
        builder.Services.AddEndpointsApiExplorer();
        builder.Services.AddSwaggerGen();

        builder.Services.AddHealthChecks();

        // Plataforma de Categorização — F1-PBI-1: cascata e Decision Store ainda são STUB/NO-OP.
        // F1-PBI-2 substitui ICategorizationCascade pelo orquestrador real (override->regra->baseline);
        // F1-PBI-4 substitui IDecisionStore pela persistência real (banco próprio da plataforma).
        builder.Services.AddSingleton<ICategorizationCascade, StubCategorizationCascade>();
        builder.Services.AddSingleton<IDecisionStore, NoOpDecisionStore>();
        builder.Services.AddSingleton<CategorizationMetrics>();

        var app = builder.Build();

        // Configure the HTTP request pipeline.
        if (app.Environment.IsDevelopment())
        {
            app.UseSwagger();
            app.UseSwaggerUI();
        }

        app.UseHttpsRedirection();

        app.UseAuthorization();

        app.MapControllers();
        app.MapHealthChecks("/health");

        app.Run();
    }
}
```

