using Pfm.Categorization.WebApi.Api.Categorize;

namespace Pfm.Categorization.WebApi.Domain.Categorize;

/// <summary>
/// Normaliza o CategorizeRequest em CategorizationContext.
/// Derivação de entity_key MÍNIMA (sem NLP, sem resolução de descriptor — RFC §4.3):
/// card -> merchant_id | pix/ted/boleto -> document | utility -> biller_id.
/// A regra COMPLETA (normalização trim/upper, casos de borda) é escopo do F1-PBI-6; aqui fica
/// o suficiente para o esqueleto do serviço responder sem travar.
/// </summary>
public static class ContextBuilder
{
    public static CategorizationContext Build(CategorizeRequest request)
    {
        var entityKey = request.Source switch
        {
            CategorizationSource.Card => request.Entity?.MerchantId,
            CategorizationSource.Pix or CategorizationSource.Ted or CategorizationSource.Boleto
                => request.Entity?.Document,
            CategorizationSource.Utility => request.Entity?.BillerId,
            _ => null
        };

        return new CategorizationContext
        {
            RequestId = request.RequestId,
            Source = request.Source,
            SourceEventId = request.SourceEventId,
            OriginalTransactionId = request.OriginalTransactionId,
            Amount = request.Amount,
            Currency = request.Currency,
            TradingAccount = request.UserScope!.TradingAccount,
            Brand = request.UserScope.Brand,
            EntityType = string.IsNullOrWhiteSpace(request.Entity?.Type) ? EntityType.Unknown : request.Entity!.Type!,
            EntityKey = string.IsNullOrWhiteSpace(entityKey) ? null : entityKey!.Trim(),
            Mcc = request.Signals?.Mcc,
            Cnae = request.Signals?.Cnae,
            Installment = request.Signals?.Installment,
            IofAmount = request.Signals?.IofAmount
        };
    }
}
