using System.Diagnostics.Metrics;

namespace Pfm.Categorization.WebApi.Observability;

/// <summary>
/// Métricas do endpoint categorize via System.Diagnostics.Metrics (nativo do .NET, zero NuGet).
/// Exportação real (Prometheus/OTLP) é decisão de infraestrutura (RFC §4.0), fora do escopo
/// desta PBI — aqui só instrumentamos o Meter para poder ser escutado depois.
/// </summary>
public sealed class CategorizationMetrics : IDisposable
{
    public const string MeterName = "Pfm.Categorization.Platform";

    private readonly Meter _meter;
    private readonly Counter<long> _requestsTotal;
    private readonly Histogram<double> _latencyMs;

    public CategorizationMetrics()
    {
        _meter = new Meter(MeterName, "1.0.0");
        _requestsTotal = _meter.CreateCounter<long>(
            "categorize.requests.total",
            unit: "{request}",
            description: "Total de chamadas a /v1/categorize, por decision_source e source.");
        _latencyMs = _meter.CreateHistogram<double>(
            "categorize.latency.ms",
            unit: "ms",
            description: "Latência do endpoint /v1/categorize.");
    }

    public void RecordRequest(string decisionSource, string source) =>
        _requestsTotal.Add(1,
            new KeyValuePair<string, object?>("decision_source", decisionSource),
            new KeyValuePair<string, object?>("source", source));

    public void RecordLatency(double elapsedMs, int statusCode) =>
        _latencyMs.Record(elapsedMs, new KeyValuePair<string, object?>("status_code", statusCode));

    public void Dispose() => _meter.Dispose();
}
