### `Api/Categorize/CategorizeRequestValidator.cs`
```csharp
using Pfm.Categorization.WebApi.Domain.Categorize;

namespace Pfm.Categorization.WebApi.Api.Categorize;

public enum CategorizeValidationOutcome { Valid, BadRequest, UnprocessableEntity }

public sealed record CategorizeValidationResult(CategorizeValidationOutcome Outcome, string? Error = null)
{
    public static readonly CategorizeValidationResult Ok = new(CategorizeValidationOutcome.Valid);
    public static CategorizeValidationResult BadRequest(string error) => new(CategorizeValidationOutcome.BadRequest, error);
    public static CategorizeValidationResult Unprocessable(string error) => new(CategorizeValidationOutcome.UnprocessableEntity, error);
}

/// <summary>
/// Validação estrutural do request (F1-PBI-1). 400 = campo obrigatório ausente/malformado.
/// 422 = campo presente mas semanticamente inválido (source ou entity.type fora do enum).
/// Validação PROFUNDA por fonte (ex.: card exige merchant_id, pix/ted/boleto exigem document) é
/// escopo do F1-PBI-3/F1-PBI-6 — aqui fica só o mínimo estrutural, para não travar o esqueleto.
/// </summary>
public static class CategorizeRequestValidator
{
    public static CategorizeValidationResult Validate(CategorizeRequest? request)
    {
        if (request is null)
            return CategorizeValidationResult.BadRequest("body vazio ou inválido.");

        if (string.IsNullOrWhiteSpace(request.RequestId))
            return CategorizeValidationResult.BadRequest("request_id é obrigatório.");

        if (string.IsNullOrWhiteSpace(request.Source))
            return CategorizeValidationResult.BadRequest("source é obrigatório.");

        if (string.IsNullOrWhiteSpace(request.SourceEventId))
            return CategorizeValidationResult.BadRequest("source_event_id é obrigatório.");

        if (request.OriginalTransactionId == Guid.Empty)
            return CategorizeValidationResult.BadRequest("original_transaction_id é obrigatório.");

        if (request.OccurredAt == default)
            return CategorizeValidationResult.BadRequest("occurred_at é obrigatório.");

        if (string.IsNullOrWhiteSpace(request.Currency))
            return CategorizeValidationResult.BadRequest("currency é obrigatório.");

        if (request.UserScope is null || request.UserScope.TradingAccount <= 0)
            return CategorizeValidationResult.BadRequest("user_scope.trading_account é obrigatório.");

        if (!CategorizationSource.IsValid(request.Source))
            return CategorizeValidationResult.Unprocessable($"source '{request.Source}' não é reconhecida.");

        if (request.Entity is not null
            && !string.IsNullOrWhiteSpace(request.Entity.Type)
            && !EntityType.IsValid(request.Entity.Type))
            return CategorizeValidationResult.Unprocessable($"entity.type '{request.Entity.Type}' não é reconhecido.");

        return CategorizeValidationResult.Ok;
    }
}
