### `Api/Categorize/CategorizeController.cs`
```csharp
using Microsoft.AspNetCore.Mvc;
using Pfm.Categorization.WebApi.Domain.Categorize;
using Pfm.Categorization.WebApi.Infrastructure.Decisions;
using Pfm.Categorization.WebApi.Observability;

namespace Pfm.Categorization.WebApi.Api.Categorize;

/// <summary>
/// Endpoint POST /v1/categorize (F1-PBI-1). Síncrono, ETL -> Plataforma, sem PII.
/// Contrato completo em docs/spec-pfm-v2-completo-pbis-card-ready.md (F1-PBI-1).
/// Invariante: SEMPRE 200 com categoria (inclusive Outros); 5xx só em falha total do serviço.
/// </summary>
[ApiController]
[Route("v1/categorize")]
public sealed class CategorizeController : ControllerBase
{
    private readonly ICategorizationCascade _cascade;
    private readonly IDecisionStore _decisionStore;
    private readonly CategorizationMetrics _metrics;
    private readonly ILogger<CategorizeController> _logger;

    public CategorizeController(
        ICategorizationCascade cascade,
        IDecisionStore decisionStore,
        CategorizationMetrics metrics,
        ILogger<CategorizeController> logger)
    {
        _cascade = cascade;
        _decisionStore = decisionStore;
        _metrics = metrics;
        _logger = logger;
    }

    [HttpPost]
    [ProducesResponseType(typeof(CategorizeResponse), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status400BadRequest)]
    [ProducesResponseType(StatusCodes.Status422UnprocessableEntity)]
    public async Task<IActionResult> Categorize([FromBody] CategorizeRequest? request, CancellationToken cancellationToken)
    {
        var validation = CategorizeRequestValidator.Validate(request);
        if (validation.Outcome == CategorizeValidationOutcome.BadRequest)
            return BadRequest(new { error = validation.Error });
        if (validation.Outcome == CategorizeValidationOutcome.UnprocessableEntity)
            return UnprocessableEntity(new { error = validation.Error });

        using var activity = CategorizationActivitySource.Instance.StartActivity("categorize");
        activity?.SetTag("request_id", request!.RequestId);
        activity?.SetTag("source", request.Source);

        using var scope = _logger.BeginScope(new Dictionary<string, object?>
        {
            ["RequestId"] = request!.RequestId,
            ["Source"] = request.Source,
            ["SourceEventId"] = request.SourceEventId
        });

        var stopwatch = System.Diagnostics.Stopwatch.StartNew();

        var context = ContextBuilder.Build(request);
        var decision = _cascade.Decide(context);
        await _decisionStore.PersistAsync(context, decision, cancellationToken);

        stopwatch.Stop();
        _metrics.RecordRequest(decision.DecisionSource, request.Source);
        _metrics.RecordLatency(stopwatch.Elapsed.TotalMilliseconds, StatusCodes.Status200OK);

        _logger.LogInformation(
            "categorize decidido: decision_source={DecisionSource} category={CategoryCode} flagged={Flagged} latency_ms={LatencyMs}",
            decision.DecisionSource, decision.ExpenseCategoryCode, decision.FlaggedForReview, stopwatch.Elapsed.TotalMilliseconds);

        var response = new CategorizeResponse
        {
            RequestId = request.RequestId,
            ExpenseCategory = new ExpenseCategoryRef { Id = decision.ExpenseCategoryId, Code = decision.ExpenseCategoryCode },
            DecisionSource = decision.DecisionSource,
            Confidence = decision.Confidence,
            FlaggedForReview = decision.FlaggedForReview,
            IsUserCategory = decision.IsUserCategory,
            Versions = new DecisionVersions
            {
                Seed = decision.SeedVersion,
                Taxonomy = decision.TaxonomyVersion,
                Rules = decision.RulesVersion
            },
            Explain = decision.Explain?.ToDictionary(kv => kv.Key, kv => kv.Value)
        };

        return Ok(response);
    }
}
